mapper.select:
SELECT FEC.PHYSIC_PORT AS physicPort, FEC.ERROR_FRAMES AS errorFrames, FEC.INVALID_CRC_COUNT AS invalidCrcCount, FEC.LOSS_OF_SIGNAL_COUNT AS lossOfSignalCount, FEC.LOSS_OF_SYNC_COUNT AS lossOfSyncCount, FEC.LINK_FAILURE_COUNT AS linkFailureCount, FEC.INVALID_TX_WORD_COUNT AS invalidTxWordCount, FEC.TIME AS time FROM TBL_FC_STORAGE_ERROR_CODE FEC WHERE PHYSIC_PORT = #{physicPort} AND TIME BETWEEN ${startTime} AND ${endTime}
AND FEC.OP_GROUP_CODE LIKE #{operatorGroupCode}
ORDER BY TIME ASC

SELECT SUM(ERROR_FRAMES) as errorFramesSum,  SUM(INVALID_CRC_COUNT) as invalidCrcCountSum, SUM(LOSS_OF_SIGNAL_COUNT) as lossOfSignalCountSum,
SUM(LOSS_OF_SYNC_COUNT) as lossOfSyncCountSum, SUM(LINK_FAILURE_COUNT) as linkFailureCountSum, SUM(INVALID_TX_WORD_COUNT) as invalidTxWordCountSum
FROM TBL_FC_STORAGE_ERROR_CODE
WHERE HOST_ID = ${hostId} AND PHYSIC_PORT = #{physicPort}

    AND TIME BETWEEN ${startTime} AND ${endTime}

GROUP BY HOST_ID, PHYSIC_PORT
LIMIT 0,${limit}
